{"file_path":"/workspace/csv_to_json.awk","content":"#!/usr/bin/awk -f
# Convert CSV to JSON array of objects
# Usage: awk -f csv_to_json.awk people.csv > people.json

BEGIN {
    FS = ","
    printf "[\n"
    first = 1
}

NR == 1 {
    # Parse header row
    for (i = 1; i <= NF; i++) {
        headers[i] = $i
    }
    next
}

{
    # Print comma between objects (except for first one)
    if (!first) {
        printf ",\n"
    }
    first = 0

    # Start JSON object
    printf "  {\n"

    # Output each field as key-value pair
    for (i = 1; i <= NF; i++) {
        printf "    \"%s\": ", headers[i]

        # Check if value should be a number
        if (headers[i] == "id" || headers[i] == "age") {
            printf "%s", $i
        } else {
            # Escape quotes and output as string
            gsub(/"/, "\\\"", $i)
            printf "\"%s\"", $i
        }

        # Add comma if not the last field
        if (i < NF) {
            printf ","
        }
        printf "\n"
    }

    # End JSON object (without comma - added on next iteration)
    printf "  }"
}

END {
    printf "\n]\n"
}
"}

